














































import Vue from "vue";

export default Vue.extend({
  components: {},
  props: {
    db: undefined,
  },
  data: () => ({}),
  computed: {
    dataBase() {
      return this.db;
    },
  },
  methods: {
    getImage(client: string, date: string): string {
      client = client.replace(/\s/g, "").toLowerCase();
      date = date.replace(/\//g, "");
      let result;
      try {
        result = require(`@/assets/${client}_${date}.jpg`);
      }
      catch (e) {
        result = require(`@/assets/miguelrivas.jpg`);
      }
      return result;

    },
  },
});
